namespace RecipeHub.Services;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string CategorySlug { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new()
        {
            Id = 1, Title = "Bruschetta", Category = "Appetizers", CategorySlug = "appetizers",
            Ingredients = ["Baguette", "Tomatoes", "Basil", "Garlic", "Olive oil"],
            Steps = ["Toast bread slices", "Dice tomatoes and mix with basil and garlic", "Top bread with tomato mixture", "Drizzle with olive oil"],
            AverageRating = 4.5, RatingCount = 12
        },
        new()
        {
            Id = 2, Title = "Stuffed Mushrooms", Category = "Appetizers", CategorySlug = "appetizers",
            Ingredients = ["Button mushrooms", "Cream cheese", "Garlic", "Breadcrumbs", "Parsley"],
            Steps = ["Remove mushroom stems", "Mix cream cheese with garlic and parsley", "Fill mushroom caps", "Top with breadcrumbs and bake at 375°F for 20 min"],
            AverageRating = 4.2, RatingCount = 8
        },
        new()
        {
            Id = 3, Title = "Spaghetti Carbonara", Category = "Main Courses", CategorySlug = "main-courses",
            Ingredients = ["Spaghetti", "Pancetta", "Eggs", "Parmesan", "Black pepper"],
            Steps = ["Cook pasta al dente", "Fry pancetta until crispy", "Whisk eggs with parmesan", "Toss hot pasta with pancetta, then egg mixture off heat"],
            AverageRating = 4.8, RatingCount = 25
        },
        new()
        {
            Id = 4, Title = "Chicken Stir Fry", Category = "Main Courses", CategorySlug = "main-courses",
            Ingredients = ["Chicken breast", "Bell peppers", "Soy sauce", "Ginger", "Rice"],
            Steps = ["Slice chicken and vegetables", "Stir fry chicken until golden", "Add vegetables and sauce", "Serve over steamed rice"],
            AverageRating = 4.3, RatingCount = 15
        },
        new()
        {
            Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", CategorySlug = "desserts",
            Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour"],
            Steps = ["Melt chocolate and butter", "Whisk eggs and sugar", "Fold in chocolate and flour", "Bake at 425°F for 12 min"],
            AverageRating = 4.9, RatingCount = 30
        },
        new()
        {
            Id = 6, Title = "Berry Smoothie", Category = "Beverages", CategorySlug = "beverages",
            Ingredients = ["Mixed berries", "Yogurt", "Honey", "Milk", "Ice"],
            Steps = ["Add all ingredients to blender", "Blend until smooth", "Pour and serve immediately"],
            AverageRating = 4.1, RatingCount = 10
        },
        new()
        {
            Id = 7, Title = "Sourdough Bread", Category = "Baking", CategorySlug = "baking",
            Ingredients = ["Bread flour", "Sourdough starter", "Water", "Salt"],
            Steps = ["Mix flour, water, and starter", "Autolyse 30 min then add salt", "Stretch and fold every 30 min for 3 hours", "Shape and cold proof overnight", "Bake in Dutch oven at 450°F"],
            AverageRating = 4.7, RatingCount = 20
        },
        new()
        {
            Id = 8, Title = "Vegetable Curry", Category = "Vegetarian", CategorySlug = "vegetarian",
            Ingredients = ["Chickpeas", "Coconut milk", "Curry paste", "Spinach", "Sweet potato"],
            Steps = ["Sauté curry paste", "Add cubed sweet potato and coconut milk", "Simmer 20 min", "Add chickpeas and spinach, cook 5 more min"],
            AverageRating = 4.6, RatingCount = 18
        }
    ];

    private int _nextId = 9;

    public List<Recipe> GetByCategory(string categorySlug)
    {
        return _recipes.Where(r => r.CategorySlug == categorySlug).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public List<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().ToList();
    }

    public void AddRecipe(string title, string category, List<string> ingredients, List<string> steps)
    {
        var slug = category.ToLowerInvariant().Replace(' ', '-');
        _recipes.Add(new Recipe
        {
            Id = _nextId++,
            Title = title,
            Category = category,
            CategorySlug = slug,
            Ingredients = ingredients,
            Steps = steps,
            AverageRating = 0,
            RatingCount = 0
        });
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is null) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount + stars;
        recipe.RatingCount++;
        recipe.AverageRating = totalStars / recipe.RatingCount;
    }
}

@page "/recipes/{CategorySlug}"
@inject RecipeHub.Services.RecipeService RecipeService

<PageTitle>@categoryName Recipes - RecipeHub</PageTitle>

<h1>@categoryName</h1>

@if (recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text text-muted">
                            ⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)
                        </p>
                        <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-outline-secondary mt-3">← Back to Categories</a>

@code {
    [Parameter]
    public string CategorySlug { get; set; } = string.Empty;

    private List<RecipeHub.Services.Recipe> recipes = [];
    private string categoryName = string.Empty;

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetByCategory(CategorySlug);
        categoryName = recipes.FirstOrDefault()?.Category ?? CategorySlug;
    }
}

@page "/recipe/{Id:int}"
@inject RecipeHub.Services.RecipeService RecipeService

@if (recipe is null)
{
    <PageTitle>Recipe Not Found - RecipeHub</PageTitle>
    <h1>Recipe Not Found</h1>
    <p>The recipe you're looking for doesn't exist.</p>
}
else
{
    <PageTitle>@recipe.Title - RecipeHub</PageTitle>

    <h1>@recipe.Title</h1>
    <p class="text-muted">Category: @recipe.Category</p>

    <h3>Ingredients</h3>
    <ul>
        @foreach (var ingredient in recipe.Ingredients)
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in recipe.Steps)
        {
            <li class="mb-2">@step</li>
        }
    </ol>

    <h3>Rate this Recipe</h3>
    <StarRating RecipeId="recipe.Id" CurrentRating="recipe.AverageRating" RatingCount="recipe.RatingCount" />

    <a href="recipes/@recipe.CategorySlug" class="btn btn-outline-secondary mt-4">← Back to @recipe.Category</a>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private RecipeHub.Services.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@inject RecipeHub.Services.RecipeService RecipeService

<div class="d-flex align-items-center gap-2">
    <div class="star-rating">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span class="star @(star <= hoverStar ? "hovered" : "") @(star <= submittedStar ? "selected" : "")"
                  @onclick="() => SubmitRating(star)"
                  @onmouseover="() => hoverStar = star"
                  @onmouseout="() => hoverStar = 0"
                  role="button"
                  title="Rate @star star(s)">
                @(star <= (hoverStar > 0 ? hoverStar : submittedStar) ? "★" : "☆")
            </span>
        }
    </div>
    <span class="text-muted ms-2">
        @if (hasRated)
        {
            <text>Thanks! You rated @submittedStar star(s).</text>
        }
        else
        {
            <text>@CurrentRating.ToString("F1") avg (@RatingCount ratings)</text>
        }
    </span>
</div>

<style>
    .star-rating .star {
        font-size: 1.8rem;
        cursor: pointer;
        color: #ccc;
        transition: color 0.15s;
    }
    .star-rating .star.hovered,
    .star-rating .star.selected {
        color: #ffc107;
    }
</style>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentRating { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int hoverStar;
    private int submittedStar;
    private bool hasRated;

    private void SubmitRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        submittedStar = stars;
        hasRated = true;

        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            CurrentRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
    }
}

@page "/submit"
@rendermode InteractiveServer
@inject RecipeHub.Services.RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe has been added to the community.
    </div>
    <a href="/" class="btn btn-primary">Back to Home</a>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="model.Title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => model.Title" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="model.Category" class="form-select">
                <option value="">-- Select a category --</option>
                <option value="Appetizers">Appetizers</option>
                <option value="Main Courses">Main Courses</option>
                <option value="Desserts">Desserts</option>
                <option value="Beverages">Beverages</option>
                <option value="Baking">Baking</option>
                <option value="Vegetarian">Vegetarian</option>
            </InputSelect>
            <ValidationMessage For="() => model.Category" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" @bind-Value="model.Ingredients" class="form-control" rows="5"
                           placeholder="1 cup flour&#10;2 eggs&#10;1/2 cup sugar" />
            <ValidationMessage For="() => model.Ingredients" class="text-danger" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" @bind-Value="model.Steps" class="form-control" rows="5"
                           placeholder="Preheat oven to 350°F&#10;Mix dry ingredients&#10;Add wet ingredients" />
            <ValidationMessage For="() => model.Steps" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeFormModel model = new();
    private bool submitted;

    private void HandleSubmit()
    {
        var ingredients = model.Ingredients
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();
        var steps = model.Steps
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();

        RecipeService.AddRecipe(model.Title, model.Category, ingredients, steps);
        submitted = true;
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required.")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "At least one ingredient is required.")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "At least one step is required.")]
        public string Steps { get; set; } = string.Empty;
    }
}

