{"path": "/tmp/sv-8543498972e9449e91e0eaca8ff0f91d/RecipeHub/Components/Pages/StarRating.razor", "file_text": "@rendermode InteractiveServer
@inject RecipeHub.Services.RecipeService RecipeService

<div class="d-flex align-items-center gap-2">
    <div class="star-rating">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span class="star @(star <= hoverStar ? "hovered" : "") @(star <= submittedStar ? "selected" : "")"
                  @onclick="() => SubmitRating(star)"
                  @onmouseover="() => hoverStar = star"
                  @onmouseout="() => hoverStar = 0"
                  role="button"
                  title="Rate @star star(s)">
                @(star <= (hoverStar > 0 ? hoverStar : submittedStar) ? "★" : "☆")
            </span>
        }
    </div>
    <span class="text-muted ms-2">
        @if (hasRated)
        {
            <text>Thanks! You rated @submittedStar star(s).</text>
        }
        else
        {
            <text>@CurrentRating.ToString("F1") avg (@RatingCount ratings)</text>
        }
    </span>
</div>

<style>
    .star-rating .star {
        font-size: 1.8rem;
        cursor: pointer;
        color: #ccc;
        transition: color 0.15s;
    }
    .star-rating .star.hovered,
    .star-rating .star.selected {
        color: #ffc107;
    }
</style>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentRating { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int hoverStar;
    private int submittedStar;
    private bool hasRated;

    private void SubmitRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        submittedStar = stars;
        hasRated = true;

        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            CurrentRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
    }
}
"}

